1	/** A live cell's position on the infinite grid as [x, y] coordinates. */
2	export type Cell = [number, number];
3	
4	/**
5	 * Computes the next generation of live cells in Conway's Game of Life.
6	 *
7	 * @param cells - The currently live cells on the infinite grid.
8	 * @returns The live cells in the next generation.
9	 */
10	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
11	  [-1, -1], [-1, 0], [-1, 1],
12	  [ 0, -1],          [ 0, 1],
13	  [ 1, -1], [ 1, 0], [ 1, 1],
14	];
15	
16	const neighborsOf = ([x, y]: Cell): Cell[] =>
17	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
18	
19	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
20	
21	export function nextGeneration(cells: Cell[]): Cell[] {
22	  const liveSet = new Set(cells.map(cellKey));
23	
24	  const countLiveNeighbors = (cell: Cell): number =>
25	    neighborsOf(cell).filter((n) => liveSet.has(cellKey(n))).length;
26	
27	  const deadNeighborCandidates = new Set<string>();
28	  for (const cell of cells) {
29	    for (const neighbor of neighborsOf(cell)) {
30	      const k = cellKey(neighbor);
31	      if (!liveSet.has(k)) deadNeighborCandidates.add(k);
32	    }
33	  }
34	
35	  const result: Cell[] = [];
36	  for (const k of deadNeighborCandidates) {
37	    const [x, y] = k.split(",").map(Number) as [number, number];
38	    if (countLiveNeighbors([x, y]) === 3) {
39	      result.push([x, y]);
40	    }
41	  }
42	  return result;
43	}
